#!/usr/bin/env bash
# topic-2.sh — 竞赛 决策助手 for 青少年编程教育.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="青少年编程教育"
TOPIC="竞赛"

usage() {
  cat <<EOF
topic-2.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 3 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-2.sh             # interactive
  ./topic-2.sh --dry-run   # walk through but no file
  ./topic-2.sh --json      # JSON to stdout
  ./topic-2.sh --explain   # show backing playbook rules + mental models
  ./topic-2.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 竞赛 主题下的 playbook 规则组合成交互树。

基于 3 条规则:
  • 如果 要判断一个孩子适合竞赛路线还是普及路线 → 则 : 则看三个信号: (a) 是否对「解出难题」本身感到快乐 (而非被家长/奖励驱动); (b) 数学基础是否在年级前 1
  • 如果 在信奥赛训练中选择 OJ 平台 → 则 : 则中国学生首选洛谷 (14000+ 题, 中文社区, CSP/NOIP 真题全覆盖), 补充 Codeforces 
  • 如果 选择机器人/硬件教育路线 → 则 : 则按预算分层: 低预算 (约 15 美元/人) → BBC micro:bit (传感器丰富 + MakeCode 

相关心智模型:
  • 制作即学习 (Making Is Learning): 编程教育的核心不是教「编程语言语法」, 而是让学生通过创造可分享的外部作品来建构内部知识 — Papert 的建构主义 (constructionism) 是整个领域的哲学根基
  • 低地板、高天花板、宽墙壁 (Low Floor, High Ceiling, Wide Walls): 好的编程教育工具必须同时满足三个维度 — 入门门槛低 (low floor, 6 岁能开始)、能力上限高 (high ceiling, 能做复杂项目)、创作方向广 (wide walls, 不限于一种

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "要判断一个孩子适合竞赛路线还是普及路线"
  "在信奥赛训练中选择 OJ 平台"
  "选择机器人/硬件教育路线"
)
declare -a RULE_ACTIONS=(
  ": 则看三个信号: (a) 是否对「解出难题」本身感到快乐 (而非被家长/奖励驱动); (b) 数学基础是否在年级前 10% (业内估); (c) 是否愿意持续投入 (每周约 10-15 小时, 业内估)"
  ": 则中国学生首选洛谷 (14000+ 题, 中文社区, CSP/NOIP 真题全覆盖), 补充 Codeforces (国际赛事训练); USACO 用于模拟美赛难度; LeetCode 不适合信奥赛 (面向面试而非竞赛)"
  ": 则按预算分层: 低预算 (约 15 美元/人) → BBC micro:bit (传感器丰富 + MakeCode 积木 + Python 双模式); 中预算 (约 100-200 美元/人) → Makeblock mBot (图形化 + Python + 金属结构); 高预算 (约 400+ 美元/人) → LEGO SPIKE Prime (成熟课程体系 + 竞赛级)"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-2-decision"
fi
